// public/firebase-messaging-sw.js
importScripts('https://www.gstatic.com/firebasejs/9.22.0/firebase-app-compat.js');
importScripts('https://www.gstatic.com/firebasejs/9.22.0/firebase-messaging-compat.js');

// Load Firebase config from auto-generated file
// This file is generated by scripts/generate-firebase-config.js during build
// and is not committed to git for security
importScripts('/firebase-config.js');

// Initialize the Firebase app in the service worker using the loaded config
firebase.initializeApp(self.FIREBASE_CONFIG);

// Retrieve an instance of Firebase Messaging so that it can handle background messages.
const messaging = firebase.messaging();

messaging.onBackgroundMessage((payload) => {
  console.log('[firebase-messaging-sw.js] Received background message ', payload);

  const notificationTitle = payload.data?.title || 'Sales Dashboard';
  const notificationOptions = {
    body: payload.data?.body || '',
    icon: '/pwa-192x192.png',
    data: {
      url: payload.data?.url || '/',
      type: payload.data?.type || ''
    }
  };

  self.registration.showNotification(notificationTitle, notificationOptions);
});

// Handle click on notification
self.addEventListener('notificationclick', function (event) {
  event.notification.close();

  const urlToOpen = event.notification.data?.url || '/';

  event.waitUntil(
    clients.matchAll({ type: 'window', includeUncontrolled: true }).then(function (windowClients) {
      for (let i = 0; i < windowClients.length; i++) {
        const client = windowClients[i];
        if (client.url === urlToOpen && 'focus' in client) {
          return client.focus();
        }
      }
      if (clients.openWindow) {
        return clients.openWindow(urlToOpen);
      }
    })
  );
});
